   293→func BuildSidecarOutboundVirtualHosts(node *model.Proxy, push *model.PushContext,
   294→	routeName string,
   295→	listenerPort int,
   296→	efKeys []string,
   297→	xdsCache model.XdsCache,
   298→) ([]*route.VirtualHost, *discovery.Resource, *istio_route.Cache) {
   299→	// Get the services from the egress listener.  When sniffing is enabled, we send
   300→	// route name as foo.bar.com:8080 which is going to match against the wildcard
   301→	// egress listener only. A route with sniffing would not have been generated if there
   302→	// was a sidecar with explicit port (and hence protocol declaration). A route with
   303→	// sniffing is generated only in the case of the catch all egress listener.
   304→	egressListener := node.SidecarScope.GetEgressListenerForRDS(listenerPort, routeName)
   305→	// We should never be getting a nil egress listener because the code that setup this RDS
   306→	// call obviously saw an egress listener
   307→	if egressListener == nil {
   308→		return nil, nil, nil
   309→	}
   310→
   311→	services := egressListener.Services()
   312→	// To maintain correctness, we should only use the virtualservices for
   313→	// this listener and not all virtual services accessible to this proxy.
   314→	virtualServices := egressListener.VirtualServices()
   315→
   316→	// When generating RDS for ports created via the SidecarScope, we treat ports as HTTP proxy style ports
   317→	// if ports protocol is HTTP_PROXY.
   318→	if egressListener.IstioListener != nil && egressListener.IstioListener.Port != nil &&
   319→		protocol.Parse(egressListener.IstioListener.Port.Protocol) == protocol.HTTP_PROXY {
   320→		listenerPort = 0
   321→	}
   322→
   323→	includeRequestAttemptCount := util.GetProxyHeaders(node, push, istionetworking.ListenerClassSidecarOutbound).IncludeRequestAttemptCount
   324→
   325→	servicesByName := make(map[host.Name]*model.Service)
   326→	for _, svc := range services {
   327→		if listenerPort == 0 {
   328→			// Take all ports when listen port is 0 (http_proxy or uds)
   329→			// Expect virtualServices to resolve to right port
   330→			servicesByName[svc.Hostname] = svc
   331→		} else if svcPort, exists := svc.Ports.GetByPort(listenerPort); exists {
   332→			h := host.Name(strings.ToLower(string(svc.Hostname)))
   333→			servicesByName[h] = &model.Service{
   334→				Hostname:       h,
   335→				DefaultAddress: svc.GetAddressForProxy(node),
   336→				ClusterVIPs:    *svc.ClusterVIPs.DeepCopy(),
   337→				MeshExternal:   svc.MeshExternal,
   338→				Resolution:     svc.Resolution,
   339→				Ports:          []*model.Port{svcPort},
   340→				Attributes: model.ServiceAttributes{
   341→					Namespace:       svc.Attributes.Namespace,
   342→					ServiceRegistry: svc.Attributes.ServiceRegistry,
   343→					Labels:          svc.Attributes.Labels,
   344→					Aliases:         svc.Attributes.Aliases,
   345→					K8sAttributes:   svc.Attributes.K8sAttributes,
   346→				},
   347→			}
   348→		}
   349→	}
   350→
   351→	var routeCache *istio_route.Cache
   352→	if listenerPort > 0 && features.EnableRDSCaching {
   353→		// sort services, ensure that routeCache calculation result is stable
   354→		services = make([]*model.Service, 0, len(servicesByName))
   355→		for _, svc := range servicesByName {
   356→			services = append(services, svc)
   357→		}
   358→		sort.SliceStable(services, func(i, j int) bool {
   359→			return services[i].Hostname <= services[j].Hostname
   360→		})
   361→		routeCache = &istio_route.Cache{
   362→			RouteName:               routeName,
   363→			ProxyVersion:            node.Metadata.IstioVersion,
   364→			ClusterID:               string(node.Metadata.ClusterID),
   365→			DNSDomain:               node.DNSDomain,
   366→			DNSCapture:              bool(node.Metadata.DNSCapture),
   367→			DNSAutoAllocate:         bool(node.Metadata.DNSAutoAllocate),
   368→			AllowAny:                util.IsAllowAnyOutbound(node),
   369→			ListenerPort:            listenerPort,
   370→			Services:                services,
   371→			VirtualServices:         virtualServices,
   372→			DelegateVirtualServices: push.DelegateVirtualServices(virtualServices),
   373→			EnvoyFilterKeys:         efKeys,
   374→		}
   375→	}
   376→
   377→	// This is hack to keep consistent with previous behavior.
   378→	if listenerPort != 80 {
   379→		// only select virtualServices that matches a service
   380→		virtualServices = selectVirtualServices(virtualServices, servicesByName)
   381→	}
   382→
   383→	mostSpecificWildcardVsIndex := egressListener.MostSpecificWildcardVirtualServiceIndex()
   384→	// Get list of virtual services bound to the mesh gateway
   385→	virtualHostWrappers := istio_route.BuildSidecarVirtualHostWrapper(routeCache, node, push,
   386→		servicesByName, virtualServices, listenerPort, mostSpecificWildcardVsIndex,
   387→	)
   388→
   389→	if features.EnableRDSCaching {
   390→		resource := xdsCache.Get(routeCache)
   391→		if resource != nil && !features.EnableUnsafeAssertions {
   392→			return nil, resource, routeCache
   393→		}
   394→	}
   395→
   396→	vHostPortMap := make(map[int][]*route.VirtualHost)
   397→	vhosts := sets.String{}
   398→	vhdomains := sets.String{}
   399→	knownFQDN := sets.String{}
   400→
   401→	buildVirtualHost := func(hostname string, vhwrapper istio_route.VirtualHostWrapper, svc *model.Service) *route.VirtualHost {
   402→		name := util.DomainName(hostname, vhwrapper.Port)
   403→		if vhosts.InsertContains(name) {
   404→			// This means this virtual host has caused duplicate virtual host name.
   405→			var msg string
   406→			if svc == nil {
   407→				msg = fmt.Sprintf("duplicate domain from virtual service: %s", name)
   408→			} else {
   409→				msg = fmt.Sprintf("duplicate domain from service: %s", name)
   410→			}
   411→			push.AddMetric(model.DuplicatedDomains, name, node.ID, msg)
   412→			return nil
   413→		}
   414→		var domains []string
   415→		var altHosts []string
   416→		if svc == nil {
   417→			if SidecarIgnorePort(node) {
   418→				domains = []string{util.IPv6Compliant(hostname)}
   419→			} else {
   420→				domains = []string{util.IPv6Compliant(hostname), name}
   421→			}
   422→		} else {
   423→			domains, altHosts = generateVirtualHostDomains(svc, listenerPort, vhwrapper.Port, node)
   424→		}
   425→		dl := len(domains)
   426→		domains = dedupeDomains(domains, vhdomains, altHosts, knownFQDN)
   427→		if dl != len(domains) {
   428→			var msg string
   429→			if svc == nil {
   430→				msg = fmt.Sprintf("duplicate domain from virtual service: %s", name)
   431→			} else {
   432→				msg = fmt.Sprintf("duplicate domain from service: %s", name)
   433→			}
   434→			// This means this virtual host has caused duplicate virtual host domain.
   435→			push.AddMetric(model.DuplicatedDomains, name, node.ID, msg)
   436→		}
   437→		if len(domains) > 0 {
   438→			pervirtualHostFilters := map[string]*anypb.Any{}
   439→			if statefulConfig := util.MaybeBuildStatefulSessionFilterConfig(svc); statefulConfig != nil {
   440→				perRouteStatefulSession := &statefulsession.StatefulSessionPerRoute{
   441→					Override: &statefulsession.StatefulSessionPerRoute_StatefulSession{
   442→						StatefulSession: statefulConfig,
   443→					},
   444→				}
   445→				pervirtualHostFilters[util.StatefulSessionFilter] = protoconv.MessageToAny(perRouteStatefulSession)
   446→			}
   447→			return &route.VirtualHost{
   448→				Name:                       name,
   449→				Domains:                    domains,
   450→				Routes:                     vhwrapper.Routes,
   451→				IncludeRequestAttemptCount: includeRequestAttemptCount,
   452→				TypedPerFilterConfig:       pervirtualHostFilters,
   453→			}
   454→		}
   455→
   456→		return nil
   457→	}
   458→
   459→	for _, virtualHostWrapper := range virtualHostWrappers {
   460→		for _, svc := range virtualHostWrapper.Services {
   461→			name := util.DomainName(string(svc.Hostname), virtualHostWrapper.Port)
   462→			knownFQDN.InsertAll(name, string(svc.Hostname))
   463→		}
   464→	}
   465→
   466→	for _, virtualHostWrapper := range virtualHostWrappers {
   467→		// If none of the routes matched by source, skip this virtual host
   468→		if len(virtualHostWrapper.Routes) == 0 {
   469→			continue
   470→		}
   471→		virtualHosts := make([]*route.VirtualHost, 0, len(virtualHostWrapper.VirtualServiceHosts)+len(virtualHostWrapper.Services))
   472→
   473→		for _, hostname := range virtualHostWrapper.VirtualServiceHosts {
   474→			if vhost := buildVirtualHost(strings.ToLower(hostname), virtualHostWrapper, nil); vhost != nil {
   475→				virtualHosts = append(virtualHosts, vhost)
   476→			}
   477→		}
   478→
   479→		for _, svc := range virtualHostWrapper.Services {
   480→			if vhost := buildVirtualHost(string(svc.Hostname), virtualHostWrapper, svc); vhost != nil {
   481→				virtualHosts = append(virtualHosts, vhost)
   482→			}
   483→		}
   484→		vHostPortMap[virtualHostWrapper.Port] = append(vHostPortMap[virtualHostWrapper.Port], virtualHosts...)
   485→	}
   486→
   487→	var out []*route.VirtualHost
   488→	if listenerPort == 0 {
   489→		out = mergeAllVirtualHosts(vHostPortMap)
   490→	} else {
   491→		out = vHostPortMap[listenerPort]
   492→	}
   493→
   494→	return out, nil, routeCache
   495→}
   496→
   497→// dedupeDomains removes the duplicate domains from the passed in domains.
   498→func dedupeDomains(domains []string, vhdomains sets.String, expandedHosts []string, knownFQDNs sets.String) []string {
   499→	temp := domains[:0]
   500→	for _, d := range domains {
   501→		if vhdomains.Contains(strings.ToLower(d)) {
   502→			continue
   503→		}
   504→		// Check if the domain is an "expanded" host, and its also a known FQDN
   505→		// This prevents a case where a domain like "foo.com.cluster.local" gets expanded to "foo.com", overwriting
   506→		// the real "foo.com"
   507→		// This works by providing a list of domains that were added as expanding the DNS domain as part of expandedHosts,
   508→		// and a list of known unexpanded FQDNs to compare against
   509→		if slices.Contains(expandedHosts, d) && knownFQDNs.Contains(d) { // O(n) search, but n is at most 10
   510→			continue
   511→		}
   512→		temp = append(temp, d)
   513→		vhdomains.Insert(strings.ToLower(d))
   514→	}
   515→	return temp
   516→}
   517→
   518→// Returns the set of virtual hosts that correspond to the listener that has HTTP protocol detection
   519→// setup. This listener should only get the virtual hosts that correspond to this service+port and not
   520→// all virtual hosts that are usually supplied for 0.0.0.0:PORT.
   521→func getVirtualHostsForSniffedServicePort(vhosts []*route.VirtualHost, routeName string) []*route.VirtualHost {
   522→	nameWithoutPort, _, _ := net.SplitHostPort(routeName)
   523→	var virtualHosts []*route.VirtualHost
   524→	for _, vh := range vhosts {
   525→		for _, domain := range vh.Domains {
   526→			if domain == routeName || domain == nameWithoutPort {
   527→				virtualHosts = append(virtualHosts, vh)
   528→				break
   529→			}
   530→		}
   531→	}
   532→
   533→	if len(virtualHosts) == 0 {
   534→		return virtualHosts
   535→	}
   536→	if len(virtualHosts) == 1 {
   537→		virtualHosts[0].Domains = []string{"*"}
   538→		return virtualHosts
   539→	}
   540→	if features.EnableUnsafeAssertions {
   541→		panic(fmt.Sprintf("unexpectedly matched multiple virtual hosts for %v: %v", routeName, virtualHosts))
   542→	}
   543→	return virtualHosts
   544→}
   545→
   546→func SidecarIgnorePort(node *model.Proxy) bool {
   547→	return !node.IsProxylessGrpc()
   548→}
   549→
   550→// generateVirtualHostDomains generates the set of domain matches for a service being accessed from
   551→// a proxy node
   552→func generateVirtualHostDomains(service *model.Service, listenerPort int, port int, node *model.Proxy) ([]string, []string) {
   553→	if SidecarIgnorePort(node) && listenerPort != 0 {
   554→		// Indicate we do not need port, as we will set IgnorePortInHostMatching
   555→		port = portNoAppendPortSuffix
   556→	}
   557→	domains := []string{}
   558→	allAltHosts := []string{}
   559→	all := []string{string(service.Hostname)}
   560→	for _, a := range service.Attributes.Aliases {
   561→		all = append(all, a.Hostname.String())
   562→	}
   563→	for _, s := range all {
   564→		altHosts := GenerateAltVirtualHosts(s, port, node.DNSDomain)
   565→		domains = appendDomainPort(domains, s, port)
   566→		domains = append(domains, altHosts...)
   567→		allAltHosts = append(allAltHosts, altHosts...)
   568→	}
   569→
   570→	if service.Resolution == model.Passthrough &&
   571→		service.Attributes.ServiceRegistry == provider.Kubernetes {
   572→		for _, domain := range domains {
   573→			domains = append(domains, wildcardDomainPrefix+domain)
   574→		}
   575→	}
   576→
   577→	for _, svcAddr := range service.GetAllAddressesForProxy(node) {
   578→		if len(svcAddr) > 0 && svcAddr != constants.UnspecifiedIP {
   579→			domains = appendDomainPort(domains, svcAddr, port)
   580→		}
   581→	}
   582→
   583→	return domains, allAltHosts
   584→}
   585→
   586→// appendDomainPort appends `domain` and `domain:port` to `domains`. The `domain:port` variant is skipped
   587→// if port is unset.
   588→func appendDomainPort(domains []string, domain string, port int) []string {
   589→	if port == portNoAppendPortSuffix {
   590→		return append(domains, util.IPv6Compliant(domain))
   591→	}
   592→	return append(domains, util.IPv6Compliant(domain), util.DomainName(domain, port))
   593→}
   594→
   595→// GenerateAltVirtualHosts given a service and a port, generates all possible HTTP Host headers.
   596→// For example, a service of the form foo.local.campus.net on port 80, with local domain "local.campus.net"
   597→// could be accessed as http://foo:80 within the .local network, as http://foo.local:80 (by other clients
   598→// in the campus.net domain), as http://foo.local.campus:80, etc.
   599→// NOTE: When a sidecar in remote.campus.net domain is talking to foo.local.campus.net,
   600→// we should only generate foo.local, foo.local.campus, etc (and never just "foo").
   601→//
   602→// - Given foo.local.campus.net on proxy domain local.campus.net, this function generates
   603→// foo:80, foo.local:80, foo.local.campus:80, with and without ports. It will not generate
   604→// foo.local.campus.net (full hostname) since its already added elsewhere.
   605→//
   606→// - Given foo.local.campus.net on proxy domain remote.campus.net, this function generates
   607→// foo.local:80, foo.local.campus:80
   608→//
   609→// - Given foo.local.campus.net on proxy domain "" or proxy domain example.com, this
   610→// function returns nil
   611→func GenerateAltVirtualHosts(hostname string, port int, proxyDomain string) []string {
   612→	var vhosts []string // Initialize the slice for alternate hosts
   613→
   614→	if features.EnableAbsoluteFqdnVhostDomain {
   615→		// Add the absolute FQDN variant (with trailing dot) if the hostname is not an IP address.
   616→		// This is considered another form of alternate host representation.
   617→		// See https://github.com/istio/istio/issues/56007 for context.
   618→		// "foo.local.campus.net" -> "foo.local.campus.net."
   619→		// "foo.bar.svc.cluster.local" -> "foo.bar.svc.cluster.local."
   620→		isIP := net.ParseIP(hostname) != nil
   621→		if !isIP {
   622→			vhosts = append(vhosts, hostname+".")
   623→		}
   624→		if port != portNoAppendPortSuffix {
   625→			vhosts = append(vhosts, util.DomainName(hostname+".", port))
   626→		}
   627→	}
   628→
   629→	// If the dns/proxy domain contains `.svc`, only services following the <ns>.svc.<suffix>
   630→	// naming convention and that share a suffix with the domain should be expanded.
   631→	if strings.Contains(proxyDomain, ".svc.") {
   632→
   633→		if strings.HasSuffix(hostname, removeSvcNamespace(proxyDomain)) {
   634→			kubeSVCAltHosts := generateAltVirtualHostsForKubernetesService(hostname, port, proxyDomain)
   635→			return append(vhosts, kubeSVCAltHosts...)
   636→		}
   637→
   638→		// Hostname is not a kube service.  It is not safe to expand the
   639→		// hostname as non-fully-qualified names could conflict with expansion of other kube service
   640→		// hostnames
   641→		return vhosts
   642→	}
   643→
   644→	uniqueHostnameParts, sharedDNSDomainParts := getUniqueAndSharedDNSDomain(hostname, proxyDomain)
   645→
   646→	// If there is no shared DNS name (e.g., foobar.com service on local.net proxy domain)
   647→	// do not generate any alternate virtual host representations
   648→	if len(sharedDNSDomainParts) == 0 {
   649→		return vhosts
   650→	}
   651→
   652→	uniqueHostname := strings.Join(uniqueHostnameParts, ".")
   653→
   654→	// Add the uniqueHost.
   655→	vhosts = appendDomainPort(vhosts, uniqueHostname, port)
   656→	if len(uniqueHostnameParts) == 2 {
   657→		// This is the case of uniqHostname having namespace already.
   658→		dnsHostName := uniqueHostname + "." + sharedDNSDomainParts[0]
   659→		vhosts = appendDomainPort(vhosts, dnsHostName, port)
   660→	}
   661→	return vhosts
   662→}
   663→
   664→// portNoAppendPortSuffix is a signal to not append port to vhost
   665→const portNoAppendPortSuffix = 0
   666→
   667→func generateAltVirtualHostsForKubernetesService(hostname string, port int, proxyDomain string) []string {
   668→	id := strings.Index(proxyDomain, ".svc.")
   669→	ih := strings.Index(hostname, ".svc.")
   670→	if ih > 0 { // Proxy and service hostname are in kube
   671→		ns := strings.Index(hostname, ".")
   672→		if ns+1 >= len(hostname) || ns+1 > ih {
   673→			// Invalid domain
   674→			return nil
   675→		}
   676→		if hostname[ns+1:ih] == proxyDomain[:id] {
   677→			// Same namespace
   678→			if port == portNoAppendPortSuffix {
   679→				return []string{
   680→					hostname[:ns],
   681→					hostname[:ih] + ".svc",
   682→					hostname[:ih],
   683→				}
   684→			}
   685→			return []string{
   686→				hostname[:ns],
   687→				util.DomainName(hostname[:ns], port),
   688→				hostname[:ih] + ".svc",
   689→				util.DomainName(hostname[:ih]+".svc", port),
   690→				hostname[:ih],
   691→				util.DomainName(hostname[:ih], port),
   692→			}
   693→		}
   694→		// Different namespace
   695→		if port == portNoAppendPortSuffix {
   696→			return []string{
   697→				hostname[:ih],
   698→				hostname[:ih] + ".svc",
   699→			}
   700→		}
   701→		return []string{
   702→			hostname[:ih],
   703→			util.DomainName(hostname[:ih], port),
   704→			hostname[:ih] + ".svc",
   705→			util.DomainName(hostname[:ih]+".svc", port),
   706→		}
   707→	}
   708→	// Proxy is in k8s, but service isn't. No alt hosts
   709→	return nil
   710→}
   711→
   712→// mergeAllVirtualHosts across all ports. On routes for ports other than port 80,
   713→// virtual hosts without an explicit port suffix (IP:PORT) should not be added
   714→func mergeAllVirtualHosts(vHostPortMap map[int][]*route.VirtualHost) []*route.VirtualHost {
   715→	var virtualHosts []*route.VirtualHost
   716→	for p, vhosts := range vHostPortMap {
   717→		if p == 80 {
   718→			virtualHosts = append(virtualHosts, vhosts...)
   719→		} else {
   720→			for _, vhost := range vhosts {
   721→				vhost.Domains = slices.FilterInPlace(vhost.Domains, func(domain string) bool {
   722→					return strings.Contains(domain, ":")
   723→				})
   724→				if len(vhost.Domains) > 0 {
   725→					virtualHosts = append(virtualHosts, vhost)
   726→				}
   727→			}
   728→		}
   729→	}
   730→	return virtualHosts
   731→}
   732→
   733→// getUniqueAndSharedDNSDomain computes the unique and shared DNS suffix from a FQDN service name and
   734→// the proxy's local domain with namespace. This is especially useful in Kubernetes environments, where
   735→// a two services can have same name in different namespaces (e.g., foo.ns1.svc.cluster.local,
   736→// foo.ns2.svc.cluster.local). In this case, if the proxy is in ns2.svc.cluster.local, then while
   737→// generating alt virtual hosts for service foo.ns1 for the sidecars in ns2 namespace, we should generate
   738→// foo.ns1, foo.ns1.svc, foo.ns1.svc.cluster.local and should not generate a virtual host called "foo" for
   739→// foo.ns1 service.
   740→// So given foo.ns1.svc.cluster.local and ns2.svc.cluster.local, this function will return
   741→// foo.ns1, and svc.cluster.local.
   742→// When given foo.ns2.svc.cluster.local and ns2.svc.cluster.local, this function will return
   743→// foo, ns2.svc.cluster.local.
   744→func getUniqueAndSharedDNSDomain(fqdnHostname, proxyDomain string) (partsUnique []string, partsShared []string) {
   745→	// split them by the dot and reverse the arrays, so that we can
   746→	// start collecting the shared bits of DNS suffix.
   747→	// E.g., foo.ns1.svc.cluster.local -> local,cluster,svc,ns1,foo
   748→	//       ns2.svc.cluster.local -> local,cluster,svc,ns2
   749→	partsFQDN := strings.Split(fqdnHostname, ".")
   750→	partsProxyDomain := strings.Split(proxyDomain, ".")
   751→	partsFQDNInReverse := slices.Reverse(partsFQDN)
   752→	partsProxyDomainInReverse := slices.Reverse(partsProxyDomain)
   753→	var sharedSuffixesInReverse []string // pieces shared between proxy and svc. e.g., local,cluster,svc
   754→
   755→	for i := 0; i < min(len(partsFQDNInReverse), len(partsProxyDomainInReverse)); i++ {
   756→		if partsFQDNInReverse[i] == partsProxyDomainInReverse[i] {
   757→			sharedSuffixesInReverse = append(sharedSuffixesInReverse, partsFQDNInReverse[i])
   758→		} else {
   759→			break
   760→		}
   761→	}
   762→
   763→	if len(sharedSuffixesInReverse) == 0 {
   764→		partsUnique = partsFQDN
   765→	} else {
   766→		// get the non shared pieces (ns1, foo) and reverse Array
   767→		partsUnique = slices.Reverse(partsFQDNInReverse[len(sharedSuffixesInReverse):])
   768→		partsShared = slices.Reverse(sharedSuffixesInReverse)
   769→	}
   770→	return partsUnique, partsShared
   771→}
   772→
   773→func buildCatchAllVirtualHost(node *model.Proxy, includeRequestAttemptCount bool, appendXForwardedHost bool) *route.VirtualHost {
   774→	if util.IsAllowAnyOutbound(node) {
   775→		egressCluster := util.PassthroughCluster
   776→		notimeout := durationpb.New(0)
   777→
   778→		// no need to check for nil value as the previous if check has checked
   779→		if node.SidecarScope.OutboundTrafficPolicy.EgressProxy != nil {
   780→			// user has provided an explicit destination for all the unknown traffic.
   781→			// build a cluster out of this destination
   782→			egressCluster = istio_route.GetDestinationCluster(node.SidecarScope.OutboundTrafficPolicy.EgressProxy,
   783→				nil, 0)
   784→		}
   785→
   786→		routeAction := &route.RouteAction{
   787→			ClusterSpecifier: &route.RouteAction_Cluster{Cluster: egressCluster},
   788→			// Disable timeout instead of assuming some defaults.
   789→			Timeout: notimeout,
   790→			// Use deprecated value for now as the replacement MaxStreamDuration has some regressions.
   791→			// nolint: staticcheck
   792→			MaxGrpcTimeout:       notimeout,
   793→			AppendXForwardedHost: appendXForwardedHost,
   794→		}
   795→
   796→		return &route.VirtualHost{
   797→			Name:    util.Passthrough,
   798→			Domains: []string{"*"},
   799→			Routes: []*route.Route{
   800→				{
   801→					Name: util.Passthrough,
   802→					Match: &route.RouteMatch{
   803→						PathSpecifier: &route.RouteMatch_Prefix{Prefix: "/"},
   804→					},
   805→					Action: &route.Route_Route{
   806→						Route: routeAction,
   807→					},
   808→				},
   809→			},
   810→			IncludeRequestAttemptCount: includeRequestAttemptCount,
   811→		}
   812→	}
   813→
   814→	return &route.VirtualHost{
   815→		Name:    util.BlackHole,
   816→		Domains: []string{"*"},
   817→		Routes: []*route.Route{
   818→			{
   819→				Name: util.BlackHole,
   820→				Match: &route.RouteMatch{
   821→					PathSpecifier: &route.RouteMatch_Prefix{Prefix: "/"},
   822→				},
   823→				Action: &route.Route_DirectResponse{
   824→					DirectResponse: &route.DirectResponseAction{
   825→						Status: 502,
   826→					},
   827→				},
   828→			},
   829→		},
   830→		IncludeRequestAttemptCount: includeRequestAttemptCount,
   831→	}
   832→}
   833→
   834→// Simply removes everything before .svc, if present
   835→func removeSvcNamespace(domain string) string {
   836→	if idx := strings.Index(domain, ".svc."); idx > 0 {
   837→		return domain[idx:]
   838→	}
   839→
   840→	return domain
   841→}
