   112→// buildSidecarInboundHTTPRouteConfig builds the route config with a single wildcard virtual host on the inbound path
   113→// TODO: trace decorators, inbound timeouts
   114→func buildSidecarInboundHTTPRouteConfig(svc *model.Service, lb *ListenerBuilder, cc inboundChainConfig) *route.RouteConfiguration {
   115→	traceOperation := telemetry.TraceOperation(string(cc.telemetryMetadata.InstanceHostname), cc.port.Port)
   116→	defaultRoute := istio_route.BuildDefaultHTTPInboundRoute(lb.node, cc.clusterName, traceOperation, cc.port.Protocol)
   117→
   118→	inboundVHost := &route.VirtualHost{
   119→		Name:    inboundVirtualHostPrefix + strconv.Itoa(cc.port.Port), // Format: "inbound|http|%d"
   120→		Domains: buildRouteVHostDomains(svc),
   121→		Routes:  []*route.Route{defaultRoute},
   122→	}
   123→
   124→	r := &route.RouteConfiguration{
   125→		Name:             cc.clusterName,
   126→		VirtualHosts:     []*route.VirtualHost{inboundVHost},
   127→		ValidateClusters: proto.BoolFalse,
   128→	}
   129→	efw := lb.push.EnvoyFilters(lb.node)
