   134→// buildSidecarOutboundHTTPRouteConfig builds an outbound HTTP Route for sidecar.
   135→// Based on port, will determine all virtual hosts that listen on the port.
   136→func (configgen *ConfigGeneratorImpl) buildSidecarOutboundHTTPRouteConfig(
   137→	node *model.Proxy,
   138→	req *model.PushRequest,
   139→	routeName string,
   140→	vHostCache map[int][]*route.VirtualHost,
   141→	efw *model.MergedEnvoyFilterWrapper,
   142→	efKeys []string,
   143→) (*discovery.Resource, bool) {
   144→	listenerPort, useSniffing, err := extractListenerPort(routeName)
   145→	if err != nil && routeName != model.RDSHttpProxy && !strings.HasPrefix(routeName, model.UnixAddressPrefix) {
   146→		// TODO: This is potentially one place where envoyFilter ADD operation can be helpful if the
   147→		// user wants to ship a custom RDS. But at this point, the match semantics are murky. We have no
   148→		// object to match upon. This needs more thought. For now, we will continue to return nil for
   149→		// unknown routes
   150→		return nil, false
   151→	}
   152→
   153→	var virtualHosts []*route.VirtualHost
   154→	var routeCache *istio_route.Cache
   155→	var resource *discovery.Resource
   156→
   157→	cacheHit := false
   158→	if useSniffing && listenerPort != 0 {
   159→		// Check if we have already computed the list of all virtual hosts for this port
   160→		// If so, then  we simply have to return only the relevant virtual hosts for
   161→		// this listener's host:port
   162→		if vhosts, exists := vHostCache[listenerPort]; exists {
   163→			virtualHosts = getVirtualHostsForSniffedServicePort(vhosts, routeName)
   164→			cacheHit = true
   165→		}
   166→	}
   167→	if !cacheHit {
   168→		virtualHosts, resource, routeCache = BuildSidecarOutboundVirtualHosts(node, req.Push, routeName, listenerPort, efKeys, configgen.Cache)
   169→		if resource != nil {
   170→			return resource, true
   171→		}
   172→		if listenerPort > 0 {
   173→			// only cache for tcp ports and not for uds
   174→			vHostCache[listenerPort] = virtualHosts
   175→		}
   176→
   177→		// FIXME: This will ignore virtual services with hostnames that do not match any service in the registry
   178→		// per api spec, these hostnames + routes should appear in the virtual hosts (think bookinfo.com and
   179→		// productpage.ns1.svc.cluster.local). See the TODO in BuildSidecarOutboundVirtualHosts for the right solution
   180→		if useSniffing {
   181→			virtualHosts = getVirtualHostsForSniffedServicePort(virtualHosts, routeName)
   182→		}
   183→	}
   184→
   185→	util.SortVirtualHosts(virtualHosts)
   186→
   187→	if !useSniffing {
   188→		ph := util.GetProxyHeaders(node, req.Push, istionetworking.ListenerClassSidecarOutbound)
   189→		appendXForwardedHost := ph.XForwardedHost
   190→		includeRequestAttemptCount := ph.IncludeRequestAttemptCount
   191→		virtualHosts = append(virtualHosts, buildCatchAllVirtualHost(node, includeRequestAttemptCount, appendXForwardedHost))
   192→	}
   193→
   194→	out := &route.RouteConfiguration{
   195→		Name:                           routeName,
   196→		VirtualHosts:                   virtualHosts,
   197→		ValidateClusters:               proto.BoolFalse,
   198→		MaxDirectResponseBodySizeBytes: istio_route.DefaultMaxDirectResponseBodySizeBytes,
   199→		IgnorePortInHostMatching:       true,
   200→	}
   201→
   202→	// apply envoy filter patches
   203→	out = envoyfilter.ApplyRouteConfigurationPatches(networking.EnvoyFilter_SIDECAR_OUTBOUND, node, efw, out)
   204→
   205→	resource = &discovery.Resource{
   206→		Name:     out.Name,
   207→		Resource: protoconv.MessageToAny(out),
   208→	}
   209→
   210→	if features.EnableRDSCaching && routeCache != nil {
   211→		configgen.Cache.Add(routeCache, req, resource)
   212→	}
   213→
   214→	return resource, false
   215→}
