   217→func extractListenerPort(routeName string) (int, bool, error) {
   218→	hasPrefix := strings.HasPrefix(routeName, model.UnixAddressPrefix)
   219→	index := strings.IndexRune(routeName, ':')
   220→	if !hasPrefix {
   221→		routeName = routeName[index+1:]
   222→	}
   223→
   224→	listenerPort, err := strconv.Atoi(routeName)
   225→	useSniffing := !hasPrefix && index != -1
   226→	return listenerPort, useSniffing, err
   227→}
