   229→// TODO: merge with IstioEgressListenerWrapper.selectVirtualServices
   230→// selectVirtualServices selects the virtual services by matching given services' host names.
   231→func selectVirtualServices(virtualServices []config.Config, servicesByName map[host.Name]*model.Service) []config.Config {
   232→	out := make([]config.Config, 0)
   233→	// As a performance optimization, find out wildcard service hosts first, so that
   234→	// if non wildcard vs hosts can't be looked up directly in the service map, only need to
   235→	// loop through wildcard service hosts instead of all.
   236→	wcSvcHosts := []host.Name{}
   237→	for svcHost := range servicesByName {
   238→		if svcHost.IsWildCarded() {
   239→			wcSvcHosts = append(wcSvcHosts, svcHost)
   240→		}
   241→	}
   242→
   243→	for i := range virtualServices {
   244→		rule := virtualServices[i].Spec.(*networking.VirtualService)
   245→		var match bool
   246→
   247→		// Selection algorithm:
   248→		// virtualservices have a list of hosts in the API spec
   249→		// if any host in the list matches one service hostname, select the virtual service
   250→		// and break out of the loop.
   251→		for _, h := range rule.Hosts {
   252→			lch := host.Name(strings.ToLower(h))
   253→			// TODO: This is a bug. VirtualServices can have many hosts
   254→			// while the user might be importing only a single host
   255→			// We need to generate a new VirtualService with just the matched host
   256→			if servicesByName[lch] != nil {
   257→				match = true
   258→				break
   259→			}
   260→
   261→			if lch.IsWildCarded() {
   262→				// Process wildcard vs host as it need to follow the slow path of
   263→				// looping through all services in the map.
   264→				for svcHost := range servicesByName {
   265→					if lch.Matches(svcHost) {
   266→						match = true
   267→						break
   268→					}
   269→				}
   270→			} else {
   271→				// If non wildcard vs host isn't be found in service map, only loop through
   272→				// wildcard service hosts to avoid repeated matching.
   273→				for _, svcHost := range wcSvcHosts {
   274→					if lch.Matches(svcHost) {
   275→						match = true
   276→						break
   277→					}
   278→				}
   279→			}
   280→
   281→			if match {
   282→				break
   283→			}
   284→		}
   285→
   286→		if match {
   287→			out = append(out, virtualServices[i])
   288→		}
   289→	}
   290→	return out
   291→}
