   293→func BuildSidecarOutboundVirtualHosts(node *model.Proxy, push *model.PushContext,
   294→	routeName string,
   295→	listenerPort int,
   296→	efKeys []string,
   297→	xdsCache model.XdsCache,
   298→) ([]*route.VirtualHost, *discovery.Resource, *istio_route.Cache) {
   299→	// Get the services from the egress listener.  When sniffing is enabled, we send
   300→	// route name as foo.bar.com:8080 which is going to match against the wildcard
   301→	// egress listener only. A route with sniffing would not have been generated if there
   302→	// was a sidecar with explicit port (and hence protocol declaration). A route with
   303→	// sniffing is generated only in the case of the catch all egress listener.
   304→	egressListener := node.SidecarScope.GetEgressListenerForRDS(listenerPort, routeName)
   305→	// We should never be getting a nil egress listener because the code that setup this RDS
   306→	// call obviously saw an egress listener
   307→	if egressListener == nil {
   308→		return nil, nil, nil
   309→	}
   310→
   311→	services := egressListener.Services()
   312→	// To maintain correctness, we should only use the virtualservices for
   313→	// this listener and not all virtual services accessible to this proxy.
   314→	virtualServices := egressListener.VirtualServices()
   315→
   316→	// When generating RDS for ports created via the SidecarScope, we treat ports as HTTP proxy style ports
   317→	// if ports protocol is HTTP_PROXY.
   318→	if egressListener.IstioListener != nil && egressListener.IstioListener.Port != nil &&
   319→		protocol.Parse(egressListener.IstioListener.Port.Protocol) == protocol.HTTP_PROXY {
   320→		listenerPort = 0
   321→	}
   322→
   323→	includeRequestAttemptCount := util.GetProxyHeaders(node, push, istionetworking.ListenerClassSidecarOutbound).IncludeRequestAttemptCount
   324→
   325→	servicesByName := make(map[host.Name]*model.Service)
   326→	for _, svc := range services {
   327→		if listenerPort == 0 {
   328→			// Take all ports when listen port is 0 (http_proxy or uds)
   329→			// Expect virtualServices to resolve to right port
   330→			servicesByName[svc.Hostname] = svc
   331→		} else if svcPort, exists := svc.Ports.GetByPort(listenerPort); exists {
   332→			h := host.Name(strings.ToLower(string(svc.Hostname)))
   333→			servicesByName[h] = &model.Service{
   334→				Hostname:       h,
   335→				DefaultAddress: svc.GetAddressForProxy(node),
   336→				ClusterVIPs:    *svc.ClusterVIPs.DeepCopy(),
   337→				MeshExternal:   svc.MeshExternal,
   338→				Resolution:     svc.Resolution,
   339→				Ports:          []*model.Port{svcPort},
   340→				Attributes: model.ServiceAttributes{
   341→					Namespace:       svc.Attributes.Namespace,
   342→					ServiceRegistry: svc.Attributes.ServiceRegistry,
   343→					Labels:          svc.Attributes.Labels,
   344→					Aliases:         svc.Attributes.Aliases,
   345→					K8sAttributes:   svc.Attributes.K8sAttributes,
   346→				},
   347→			}
   348→		}
   349→	}
   350→
   351→	var routeCache *istio_route.Cache
   352→	if listenerPort > 0 && features.EnableRDSCaching {
   353→		// sort services, ensure that routeCache calculation result is stable
   354→		services = make([]*model.Service, 0, len(servicesByName))
   355→		for _, svc := range servicesByName {
   356→			services = append(services, svc)
   357→		}
   358→		sort.SliceStable(services, func(i, j int) bool {
   359→			return services[i].Hostname <= services[j].Hostname
   360→		})
   361→		routeCache = &istio_route.Cache{
   362→			RouteName:               routeName,
   363→			ProxyVersion:            node.Metadata.IstioVersion,
   364→			ClusterID:               string(node.Metadata.ClusterID),
   365→			DNSDomain:               node.DNSDomain,
   366→			DNSCapture:              bool(node.Metadata.DNSCapture),
   367→			DNSAutoAllocate:         bool(node.Metadata.DNSAutoAllocate),
   368→			AllowAny:                util.IsAllowAnyOutbound(node),
   369→			ListenerPort:            listenerPort,
   370→			Services:                services,
   371→			VirtualServices:         virtualServices,
   372→			DelegateVirtualServices: push.DelegateVirtualServices(virtualServices),
   373→			EnvoyFilterKeys:         efKeys,
   374→		}
   375→	}
   376→
   377→	// This is hack to keep consistent with previous behavior.
   378→	if listenerPort != 80 {
   379→		// only select virtualServices that matches a service
   380→		virtualServices = selectVirtualServices(virtualServices, servicesByName)
   381→	}
   382→
   383→	mostSpecificWildcardVsIndex := egressListener.MostSpecificWildcardVirtualServiceIndex()
   384→	// Get list of virtual services bound to the mesh gateway
   385→	virtualHostWrappers := istio_route.BuildSidecarVirtualHostWrapper(routeCache, node, push,
   386→		servicesByName, virtualServices, listenerPort, mostSpecificWildcardVsIndex,
   387→	)
   388→
   389→	if features.EnableRDSCaching {
   390→		resource := xdsCache.Get(routeCache)
   391→		if resource != nil && !features.EnableUnsafeAssertions {
   392→			return nil, resource, routeCache
   393→		}
   394→	}
   395→
   396→	vHostPortMap := make(map[int][]*route.VirtualHost)
   397→	vhosts := sets.String{}
   398→	vhdomains := sets.String{}
   399→	knownFQDN := sets.String{}
   400→
   401→	buildVirtualHost := func(hostname string, vhwrapper istio_route.VirtualHostWrapper, svc *model.Service) *route.VirtualHost {
   402→		name := util.DomainName(hostname, vhwrapper.Port)
   403→		if vhosts.InsertContains(name) {
   404→			// This means this virtual host has caused duplicate virtual host name.
   405→			var msg string
   406→			if svc == nil {
   407→				msg = fmt.Sprintf("duplicate domain from virtual service: %s", name)
   408→			} else {
   409→				msg = fmt.Sprintf("duplicate domain from service: %s", name)
   410→			}
   411→			push.AddMetric(model.DuplicatedDomains, name, node.ID, msg)
   412→			return nil
   413→		}
   414→		var domains []string
   415→		var altHosts []string
   416→		if svc == nil {
   417→			if SidecarIgnorePort(node) {
   418→				domains = []string{util.IPv6Compliant(hostname)}
   419→			} else {
   420→				domains = []string{util.IPv6Compliant(hostname), name}
   421→			}
   422→		} else {
   423→			domains, altHosts = generateVirtualHostDomains(svc, listenerPort, vhwrapper.Port, node)
   424→		}
   425→		dl := len(domains)
   426→		domains = dedupeDomains(domains, vhdomains, altHosts, knownFQDN)
   427→		if dl != len(domains) {
   428→			var msg string
   429→			if svc == nil {
   430→				msg = fmt.Sprintf("duplicate domain from virtual service: %s", name)
   431→			} else {
   432→				msg = fmt.Sprintf("duplicate domain from service: %s", name)
   433→			}
   434→			// This means this virtual host has caused duplicate virtual host domain.
   435→			push.AddMetric(model.DuplicatedDomains, name, node.ID, msg)
   436→		}
   437→		if len(domains) > 0 {
   438→			pervirtualHostFilters := map[string]*anypb.Any{}
   439→			if statefulConfig := util.MaybeBuildStatefulSessionFilterConfig(svc); statefulConfig != nil {
   440→				perRouteStatefulSession := &statefulsession.StatefulSessionPerRoute{
   441→					Override: &statefulsession.StatefulSessionPerRoute_StatefulSession{
   442→						StatefulSession: statefulConfig,
   443→					},
   444→				}
   445→				pervirtualHostFilters[util.StatefulSessionFilter] = protoconv.MessageToAny(perRouteStatefulSession)
   446→			}
   447→			return &route.VirtualHost{
   448→				Name:                       name,
   449→				Domains:                    domains,
   450→				Routes:                     vhwrapper.Routes,
   451→				IncludeRequestAttemptCount: includeRequestAttemptCount,
   452→				TypedPerFilterConfig:       pervirtualHostFilters,
   453→			}
   454→		}
   455→
   456→		return nil
   457→	}
   458→
   459→	for _, virtualHostWrapper := range virtualHostWrappers {
   460→		for _, svc := range virtualHostWrapper.Services {
   461→			name := util.DomainName(string(svc.Hostname), virtualHostWrapper.Port)
   462→			knownFQDN.InsertAll(name, string(svc.Hostname))
   463→		}
   464→	}
   465→
   466→	for _, virtualHostWrapper := range virtualHostWrappers {
   467→		// If none of the routes matched by source, skip this virtual host
   468→		if len(virtualHostWrapper.Routes) == 0 {
   469→			continue
   470→		}
   471→		virtualHosts := make([]*route.VirtualHost, 0, len(virtualHostWrapper.VirtualServiceHosts)+len(virtualHostWrapper.Services))
   472→
   473→		for _, hostname := range virtualHostWrapper.VirtualServiceHosts {
   474→			if vhost := buildVirtualHost(strings.ToLower(hostname), virtualHostWrapper, nil); vhost != nil {
   475→				virtualHosts = append(virtualHosts, vhost)
   476→			}
   477→		}
   478→
   479→		for _, svc := range virtualHostWrapper.Services {
   480→			if vhost := buildVirtualHost(string(svc.Hostname), virtualHostWrapper, svc); vhost != nil {
   481→				virtualHosts = append(virtualHosts, vhost)
   482→			}
   483→		}
   484→		vHostPortMap[virtualHostWrapper.Port] = append(vHostPortMap[virtualHostWrapper.Port], virtualHosts...)
   485→	}
   486→
   487→	var out []*route.VirtualHost
   488→	if listenerPort == 0 {
   489→		out = mergeAllVirtualHosts(vHostPortMap)
   490→	} else {
   491→		out = vHostPortMap[listenerPort]
   492→	}
   493→
   494→	return out, nil, routeCache
   495→}
