   497→// dedupeDomains removes the duplicate domains from the passed in domains.
   498→func dedupeDomains(domains []string, vhdomains sets.String, expandedHosts []string, knownFQDNs sets.String) []string {
   499→	temp := domains[:0]
   500→	for _, d := range domains {
   501→		if vhdomains.Contains(strings.ToLower(d)) {
   502→			continue
   503→		}
   504→		// Check if the domain is an "expanded" host, and its also a known FQDN
   505→		// This prevents a case where a domain like "foo.com.cluster.local" gets expanded to "foo.com", overwriting
   506→		// the real "foo.com"
   507→		// This works by providing a list of domains that were added as expanding the DNS domain as part of expandedHosts,
   508→		// and a list of known unexpanded FQDNs to compare against
   509→		if slices.Contains(expandedHosts, d) && knownFQDNs.Contains(d) { // O(n) search, but n is at most 10
   510→			continue
   511→		}
   512→		temp = append(temp, d)
   513→		vhdomains.Insert(strings.ToLower(d))
   514→	}
   515→	return temp
   516→}
   517→
   518→// Returns the set of virtual hosts that correspond to the listener that has HTTP protocol detection
   519→// setup. This listener should only get the virtual hosts that correspond to this service+port and not
   520→// all virtual hosts that are usually supplied for 0.0.0.0:PORT.
   521→func getVirtualHostsForSniffedServicePort(vhosts []*route.VirtualHost, routeName string) []*route.VirtualHost {
   522→	nameWithoutPort, _, _ := net.SplitHostPort(routeName)
   523→	var virtualHosts []*route.VirtualHost
   524→	for _, vh := range vhosts {
   525→		for _, domain := range vh.Domains {
   526→			if domain == routeName || domain == nameWithoutPort {
   527→				virtualHosts = append(virtualHosts, vh)
   528→				break
   529→			}
   530→		}
   531→	}
   532→
   533→	if len(virtualHosts) == 0 {
   534→		return virtualHosts
   535→	}
   536→	if len(virtualHosts) == 1 {
   537→		virtualHosts[0].Domains = []string{"*"}
   538→		return virtualHosts
   539→	}
   540→	if features.EnableUnsafeAssertions {
   541→		panic(fmt.Sprintf("unexpectedly matched multiple virtual hosts for %v: %v", routeName, virtualHosts))
   542→	}
   543→	return virtualHosts
   544→}
