   712→// mergeAllVirtualHosts across all ports. On routes for ports other than port 80,
   713→// virtual hosts without an explicit port suffix (IP:PORT) should not be added
   714→func mergeAllVirtualHosts(vHostPortMap map[int][]*route.VirtualHost) []*route.VirtualHost {
   715→	var virtualHosts []*route.VirtualHost
   716→	for p, vhosts := range vHostPortMap {
   717→		if p == 80 {
   718→			virtualHosts = append(virtualHosts, vhosts...)
   719→		} else {
   720→			for _, vhost := range vhosts {
   721→				vhost.Domains = slices.FilterInPlace(vhost.Domains, func(domain string) bool {
   722→					return strings.Contains(domain, ":")
   723→				})
   724→				if len(vhost.Domains) > 0 {
   725→					virtualHosts = append(virtualHosts, vhost)
   726→				}
   727→			}
   728→		}
   729→	}
   730→	return virtualHosts
   731→}
   732→
   733→// getUniqueAndSharedDNSDomain computes the unique and shared DNS suffix from a FQDN service name and
   734→// the proxy's local domain with namespace. This is especially useful in Kubernetes environments, where
   735→// a two services can have same name in different namespaces (e.g., foo.ns1.svc.cluster.local,
   736→// foo.ns2.svc.cluster.local). In this case, if the proxy is in ns2.svc.cluster.local, then while
   737→// generating alt virtual hosts for service foo.ns1 for the sidecars in ns2 namespace, we should generate
   738→// foo.ns1, foo.ns1.svc, foo.ns1.svc.cluster.local and should not generate a virtual host called "foo" for
   739→// foo.ns1 service.
   740→// So given foo.ns1.svc.cluster.local and ns2.svc.cluster.local, this function will return
   741→// foo.ns1, and svc.cluster.local.
   742→// When given foo.ns2.svc.cluster.local and ns2.svc.cluster.local, this function will return
   743→// foo, ns2.svc.cluster.local.
   744→func getUniqueAndSharedDNSDomain(fqdnHostname, proxyDomain string) (partsUnique []string, partsShared []string) {
   745→	// split them by the dot and reverse the arrays, so that we can
   746→	// start collecting the shared bits of DNS suffix.
   747→	// E.g., foo.ns1.svc.cluster.local -> local,cluster,svc,ns1,foo
   748→	//       ns2.svc.cluster.local -> local,cluster,svc,ns2
   749→	partsFQDN := strings.Split(fqdnHostname, ".")
   750→	partsProxyDomain := strings.Split(proxyDomain, ".")
   751→	partsFQDNInReverse := slices.Reverse(partsFQDN)
   752→	partsProxyDomainInReverse := slices.Reverse(partsProxyDomain)
   753→	var sharedSuffixesInReverse []string // pieces shared between proxy and svc. e.g., local,cluster,svc
   754→
   755→	for i := 0; i < min(len(partsFQDNInReverse), len(partsProxyDomainInReverse)); i++ {
   756→		if partsFQDNInReverse[i] == partsProxyDomainInReverse[i] {
   757→			sharedSuffixesInReverse = append(sharedSuffixesInReverse, partsFQDNInReverse[i])
   758→		} else {
   759→			break
   760→		}
   761→	}
   762→
   763→	if len(sharedSuffixesInReverse) == 0 {
   764→		partsUnique = partsFQDN
   765→	} else {
   766→		// get the non shared pieces (ns1, foo) and reverse Array
   767→		partsUnique = slices.Reverse(partsFQDNInReverse[len(sharedSuffixesInReverse):])
   768→		partsShared = slices.Reverse(sharedSuffixesInReverse)
   769→	}
   770→	return partsUnique, partsShared
   771→}
