   834→// Simply removes everything before .svc, if present
   835→func removeSvcNamespace(domain string) string {
   836→	if idx := strings.Index(domain, ".svc."); idx > 0 {
   837→		return domain[idx:]
   838→	}
   839→
   840→	return domain
   841→}
